import './App.css';
import { Routes, Route } from 'react-router-dom';
import YazanHomePage from './pages/home-page/HomePage.jsx';
import AuthPage from './pages/home-page/auth/AuthPage.jsx';
import 'bootstrap/dist/css/bootstrap.min.css';
import Navbar from './pages/Navbar';
import SuggestMajors from './pages/suggest-majors/SuggestMajors';
import About from './pages/suggest-majors/About';

function App() {
  return (
    <>
      <Navbar />
      <Routes>
        <Route path="/" element={<YazanHomePage />} />
        <Route path="/login" element={<AuthPage />} />
        <Route path="/suggest-majors" element={<SuggestMajors />} />
        <Route path="/about" element={<About />} />
      </Routes>
    </>
  );
}

export default App;
